const original = $("normalize_reschedule_input").first().json;

const activeAppointment = $json.id
  ? {
      id: $json.id,
      event_id: $json.event_id,
      conversation_id: $json.conversation_id,
      start_at: $json.start_at,
      end_at: $json.end_at,
      summary: $json.summary,
      description: $json.description,
      status: $json.status,
      service_address: $json.service_address,
      address_reference: $json.address_reference
    }
  : null;

return [{
  ...original,
  active_appointment: activeAppointment,
  notes: [
    ...(original.notes || []),
    activeAppointment ? "active_appointment_found" : "no_active_appointment_found"
  ]
}];

return [{
  ...$json,
  message_to_send:
    "No encontré una reserva activa para reprogramar. Si quieres, puedo ayudarte a agendar una nueva.",
  db_operations: ["messages", "lead_state"],
  state_update: {
    ...($json.state_update || {}),
    last_bot_action: "reschedule_no_active_appointment",
    next_goal: "offer_booking",
    missing_fields: []
  },
  notes: [
    ...($json.notes || []),
    "reschedule_blocked_no_active_appointment"
  ]
}];

const slots = Array.isArray($json.slots) ? $json.slots : [];
const availabilityLabel = $json.availability_label || "los próximos días";

function formatSlot(slot) {
  const start = new Date(slot.slot_start_at);

  const fecha = start.toLocaleDateString("es-CL", {
    timeZone: "America/Santiago",
    weekday: "long",
    day: "2-digit",
    month: "long"
  });

  const hora = start.toLocaleTimeString("es-CL", {
    timeZone: "America/Santiago",
    hour: "2-digit",
    minute: "2-digit"
  });

  return `${fecha} a las ${hora}`;
}

if (slots.length === 0) {
  return [{
    ...$json,
    message_to_send:
      `Claro, podemos reprogramar, pero por ahora no encontré horarios disponibles para ${availabilityLabel}. Te puedo ayudar a revisar otra alternativa.`,
    db_operations: ["messages", "lead_state"],
    state_update: {
      ...($json.state_update || {}),
      stage: "reschedule",
      next_goal: "manual_availability_review",
      last_bot_action: "reschedule_no_slots_found",
      missing_fields: [],
      booking_options: []
    },
    notes: [
      ...($json.notes || []),
      "reschedule_no_available_slots"
    ]
  }];
}

const lines = slots.map((slot, index) => {
  return `${index + 1}. ${formatSlot(slot)}`;
});

const optionNumbers = slots.map((_, index) => index + 1).join(", ");

return [{
  ...$json,
  message_to_send:
    `Claro, podemos reprogramar. Tengo estos horarios disponibles para ${availabilityLabel}:\n\n` +
    `${lines.join("\n")}\n\n` +
    `¿Cuál te acomoda? Puedes responder con ${optionNumbers}.`,
  db_operations: ["messages", "lead_state"],
  state_update: {
    ...($json.state_update || {}),
    stage: "reschedule",
    intent_last: "reschedule_requested",
    next_goal: "collect_selected_slot",
    last_bot_action: "offer_reschedule_slots",
    missing_fields: [],
    booking_options: slots,
    availability_window: $json.availability_window || "this_week",
    availability_label: availabilityLabel
  },
  notes: [
    ...($json.notes || []),
    "reschedule_slots_sent"
  ]
}];

return [{
  ...$json,
  message_to_send:
    "Ese horario ya no está disponible. Te puedo proponer otro horario para reprogramar.",
  db_operations: ["messages", "lead_state"],
  state_update: {
    ...($json.state_update || {}),
    stage: "reschedule",
    next_goal: "collect_new_slot",
    last_bot_action: "reschedule_slot_unavailable",
    availability_confirmed: false,
    missing_fields: []
  },
  notes: [
    ...($json.notes || []),
    "reschedule_slot_unavailable"
  ]
}];

const original = $("merge_slot_check_with_context").first().json;

return [{
  ...original,
  calendar_rescheduled: true,
  calendar_event_id:
    $json.id ||
    original.active_appointment?.event_id ||
    null,
  calendar_result: $json,
  notes: [
    ...(original.notes || []),
    "calendar_event_rescheduled"
  ]
}];

function serviceLabel(service) {
  const map = {
    lavado_basico: "lavado básico",
    lavado_premium: "lavado premium",
    encerado_full: "encerado full",

    lavado_profundo: "lavado premium",
    lavado_esencial: "lavado básico",
  };

  return map[service] || "el servicio";
}

const service = serviceLabel($json.service_interest);

return [{
  ...$json,
  message_to_send: `Listo, tu ${service} quedó reprogramado para el ${fecha} a las ${hora}.`,
  db_operations: ["appointments", "followups", "messages", "lead_state"],
  state_update: {
    ...($json.state_update || {}),
    stage: "booked",
    intent_last: "reschedule_confirmed",
    next_goal: "pre_service_reminder",
    last_bot_action: "reschedule_booking",
    booking_date: null,
    booking_time: null,
    slot_id: null,
    availability_confirmed: null,
    missing_fields: []
  },
  notes: [
    ...($json.notes || []),
    "booking_rescheduled"
  ]
}];

const original = (() => {
  try {
    return $("reschedule_booking").first().json;
  } catch {
    return {};
  }
})();

const data = {
  ...original,
  ...$json,
  execution_context: {
    ...(original.execution_context || {}),
    ...($json.execution_context || {})
  },
  context_packet: $json.context_packet || original.context_packet || {},
  decision: $json.decision || original.decision || {}
};

const outcome =
  data.outcome ||
  data.execution_result?.outcome ||
  data.result?.outcome ||
  (
    data.active_appointment_found === false ||
    data.active_appointment === null ||
    data.appointment === null
      ? "no_active_appointment"
      : "active_appointment_found"
  );

const finalMessage =
  data.message_to_send ||
  data.message ||
  (
    outcome === "no_active_appointment"
      ? "Revisé y no encontré una reserva activa asociada a este número. Si quieres, puedo ayudarte a agendar una nueva hora."
      : "Perfecto, te ayudo a reprogramar tu reserva. Te mostraré los horarios disponibles."
  );

return [{
  ...data,

  action: "reschedule_booking",
  outcome,

  message_to_send: finalMessage,
  message: finalMessage,

  db_operations: ["messages", "lead_state"],

  state_update: {
    ...(data.state_update || {}),
    stage: outcome === "active_appointment_found"
      ? "reschedule"
      : data.context_packet?.state?.stage,
    intent_last: outcome,
    next_goal: outcome === "no_active_appointment"
      ? "book_appointment"
      : "show_available_slots",
    last_bot_action: outcome === "no_active_appointment"
      ? "reschedule_no_active_appointment"
      : "reschedule_booking",
    missing_fields: []
  },

  execution_result: {
    ...(data.execution_result || {}),
    success: true,
    action: "reschedule_booking",
    outcome,
    bot: finalMessage
  },

  notes: [
    ...(data.notes || []),
    `reschedule_booking_outcome_${outcome}`
  ]
}];

